package io.scanbot.sdk.reactnative.components.cropping_view

import com.facebook.react.bridge.Arguments
import com.facebook.react.bridge.WritableMap
import io.scanbot.sdk.reactnative.models.BaseEvent
import io.scanbot.sdk.reactnative.models.CroppingViewCroppedAreaResult
import io.scanbot.sdk_wrapper.SBWrapper

class CroppingViewExtractCroppedAreaEvent(private val result: CroppingViewCroppedAreaResult) : BaseEvent {

    companion object {
        const val NAME = "croppedAreaResult"
    }

    override val eventName = NAME

    override fun parseData(): WritableMap {
        return Arguments.createMap().apply {
            putString("result", SBWrapper.gson.toJson(result))
        }
    }
}

class CroppingViewErrorEvent(private val errorMessage: String) : BaseEvent {

    companion object {
        const val NAME = "error"
    }

    override val eventName = NAME

    override fun parseData(): WritableMap {
        return Arguments.createMap().apply {
            putString("result", errorMessage)
        }
    }
}